parameters.jsCode:
// Parse the OpenAI response and extract scenes
const response = JSON.parse($input.item.json.choices[0].message.content);

const outputItems = [
  {
    json: {
      title: response.title,
      hook: response.hook,
      fullScript: response.scenes.map(s => s.text).join(' '),
      scenes: response.scenes,
      cta: response.cta,
      totalScenes: response.scenes.length
    }
  }
];

return outputItems;

// Generate FFmpeg command to combine video and audio
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

// Create temp directory
const tempDir = '/tmp/n8n-videos';
if (!fs.existsSync(tempDir)) {
  fs.mkdirSync(tempDir, { recursive: true });
}

const timestamp = Date.now();
const videoPath = path.join(tempDir, `video-${timestamp}.mp4`);
const audioPath = path.join(tempDir, `audio-${timestamp}.mp3`);
const outputPath = path.join(tempDir, `final-${timestamp}.mp4`);

// Save video file
const videoBuffer = Buffer.from($input.item.binary.videoData.data, 'base64');
fs.writeFileSync(videoPath, videoBuffer);

// Save audio file
const audioBuffer = Buffer.from($input.item.binary.voiceoverData.data, 'base64');
fs.writeFileSync(audioPath, audioBuffer);

// Get video duration
const duration = parseInt($input.item.json.duration || '60');

// FFmpeg command to:
// 1. Trim video to duration
// 2. Add audio
// 3. Add fade in/out
// 4. Optimize for mobile
const command = `ffmpeg -i "${videoPath}" -i "${audioPath}" \
  -t ${duration} \
  -c:v libx264 -preset fast -crf 22 \
  -c:a aac -b:a 192k \
  -vf "fade=t=in:st=0:d=0.5,fade=t=out:st=${duration - 0.5}:d=0.5,scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2" \
  -movflags +faststart \
  -y "${outputPath}"`;

try {
  execSync(command, { stdio: 'pipe' });

  // Read final video
  const finalVideo = fs.readFileSync(outputPath);

  // Cleanup temp files
  fs.unlinkSync(videoPath);
  fs.unlinkSync(audioPath);

  return [{
    json: {
      ...$input.item.json,
      outputPath,
      fileSize: finalVideo.length,
      status: 'success'
    },
    binary: {
      finalVideo: {
        data: finalVideo.toString('base64'),
        mimeType: 'video/mp4',
        fileName: `viral-video-${timestamp}.mp4`,
        fileExtension: 'mp4'
      }
    }
  }];
} catch (error) {
  return [{
    json: {
      status: 'error',
      error: error.message
    }
  }];
}

// Generate SRT subtitle file
const scenes = $input.item.json.scenes || [];
let srtContent = '';
let currentTime = 0;

scenes.forEach((scene, index) => {
  const duration = scene.duration || 8;
  const startTime = currentTime;
  const endTime = currentTime + duration;

  srtContent += `${index + 1}\n`;
  srtContent += `${formatSrtTime(startTime)} --> ${formatSrtTime(endTime)}\n`;
  srtContent += `${scene.text}\n\n`;

  currentTime = endTime;
});

function formatSrtTime(seconds) {
  const h = Math.floor(seconds / 3600).toString().padStart(2, '0');
  const m = Math.floor((seconds % 3600) / 60).toString().padStart(2, '0');
  const s = Math.floor(seconds % 60).toString().padStart(2, '0');
  const ms = Math.floor((seconds % 1) * 1000).toString().padStart(3, '0');
  return `${h}:${m}:${s},${ms}`;
}

return [{
  json: {
    ...$input.item.json,
    srtContent
  },
  binary: $input.item.binary
}];

// Add captions to video using FFmpeg
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const tempDir = '/tmp/n8n-videos';
const timestamp = Date.now();
const srtPath = path.join(tempDir, `captions-${timestamp}.srt`);
const inputPath = $input.item.json.outputPath;
const finalPath = path.join(tempDir, `captioned-${timestamp}.mp4`);

// Save SRT file
fs.writeFileSync(srtPath, $input.item.json.srtContent);

// Add captions with styling
const command = `ffmpeg -i "${inputPath}" \
  -vf "subtitles=${srtPath}:force_style='FontName=Arial,FontSize=24,Bold=1,PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,Outline=2,Shadow=1,Alignment=2,MarginV=40'" \
  -c:a copy \
  -y "${finalPath}"`;

try {
  execSync(command, { stdio: 'pipe' });

  const finalVideo = fs.readFileSync(finalPath);

  // Cleanup
  fs.unlinkSync(inputPath);
  fs.unlinkSync(srtPath);

  return [{
    json: {
      ...$input.item.json,
      finalPath,
      captionsAdded: true
    },
    binary: {
      finalVideo: {
        data: finalVideo.toString('base64'),
        mimeType: 'video/mp4',
        fileName: `viral-video-${timestamp}.mp4`,
        fileExtension: 'mp4'
      }
    }
  }];
} catch (error) {
  return [{
    json: {
      ...$input.item.json,
      captionsError: error.message
    },
    binary: $input.item.binary
  }];
}

